import WidgetKit
import SwiftUI
import AppIntents
import RealityKit

struct TrophyIntent: AppIntent {
    static var title: LocalizedStringResource = 'Trophy'
    @Parameter(title: 'Trophy Type') var trophyType: String
}

struct TrophyWidget: Widget {
    var body: some WidgetConfiguration {
        AppIntentConfiguration(
            kind: 'TrophyWidget',
            intent: TrophyIntent.self,
            provider: .static
        ) { entry in
            RealityView { content in
                if let model = try? await ModelEntity(named: entry.trophyType) {
                    content.add(model)
                }
            }
        }
    }
}

