import SwiftUI

struct NotificationListView: View {
    @State private var selected: Int?
    var body: some View {
        FocusedContent(selected: $selected) {
            ForEach(0..<6) { i in
                Text("Notification \(i)")
                    .background(selected == i ? Color.red : Color.clear)
            }
        }
    }
}

